// Generate alert for high error rate
const data = $input.all()[0].json;

const alert = {
  client_id: data.client_id,
  alert_type: 'high_error_rate',
  alert_severity: data.error_rate > 20 ? 'critical' : 'high',
  alert_title: `High Error Rate: ${data.workflow_name}`,
  alert_message: `Workflow ${data.workflow_name} has ${data.error_rate}% error rate (${data.failed_executions} failures out of ${data.total_executions} executions in last hour)`,
  source_workflow: data.workflow_name,
  source_entity_type: 'workflow',
  source_entity_id: null,
  metadata: JSON.stringify({
    total_executions: data.total_executions,
    failed_executions: data.failed_executions,
    error_rate: data.error_rate,
    time_period: '1 hour'
  }),
  triggered_at: new Date().toISOString(),
  acknowledged: false,
  acknowledged_by: null,
  acknowledged_at: null,
  notification_channels: JSON.stringify(['email', 'slack'])
};

return [{ json: alert }];

